import pytest
import torch
import ttnn
import torch.nn.functional as F

from .layer_norm_rm import layer_norm_rm


def pytorch_reference(input_tensor, gamma):
    """PyTorch reference for this stage."""
    return F.layer_norm(input_tensor, [input_tensor.shape[-1]], eps=1e-5) * gamma


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 64), id="1x1x32x64"),
        pytest.param((1, 1, 64, 64), id="1x1x64x64"),
        pytest.param((2, 1, 64, 64), id="2x1x64x64"),
    ],
)
def test_gamma(device, shape):
    """Verify normalization with gamma (scale) only."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma = torch.randn(1, 1, 1, shape[-1], dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input, gamma)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tt = ttnn.from_torch(
        gamma,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input, gamma_tt)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.02,
        atol=0.02,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
